const grpc = require('grpc');
const metadata = new grpc.Metadata();

// Accept custom headers from HTTP requests and inject them into gRPC metadata using metadata.add()
function forwardHeaders(headers) {
  for (let header of Object.keys(headers)) {
    if (header !== 'user-agent' && header !== 'x-forwarded-for') {
      metadata.add(header, headers[header]);
    }
  }
}

// Pass headers like user-agent, x-forwarded-for, and custom headers directly to backend services
function forwardHeadersToBackend(headers) {
  const backendService = grpc.createClient('backendService', 'localhost:50051');
  const request = new grpc.Request();
  request.setMetadata(metadata);
  backendService.send(request, (err, response) => {
    if (err) {
      console.error(err);
    } else {
      console.log(response);
    }
  });
}

// Prevent grpc security
function preventGrpcSecurity() {
  const grpc = require('grpc');
  const metadata = new grpc.Metadata();
  metadata.add('user-agent', 'My API Gateway');
  metadata.add('x-forwarded-for', '127.0.0.1');
  return metadata;
}